class Fan:    SLOW = 1    MIDIUM = 2    FAST = 3    def __init__(self, speed = MIDIUM, radius = 5.0, color = "BLUE", on = False ):        self.speed = speed        self.radius = radius        self.color = color        self.on = on    def get_speed(self): #getters        return self.speed    def get_radius(self):        return self.radius    def get_color(self):        return self.color    def is_on(self):        return self.on    def set_speed(self, speed): #setters        self.speed = speed    def set_radius(self, radius):        self.radius = radius    def set_color(self, color):        self.color = color    def set_on(self, on):        self.on = on